import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,c as o,e as a}from"./app.b6fba8d5.js";const i={},r=a('<h1 id="home" tabindex="-1"><a class="header-anchor" href="#home" aria-hidden="true">#</a> Home</h1><p>This wiki describes the latest version of Immersive Portals Mod (ImmPtl) Fabric version.</p><p><a href="https://github.com/qouteall/immptl" target="_blank" rel="noopener noreferrer">This wiki on GitHub</a></p><h2 id="common-questions" tabindex="-1"><a class="header-anchor" href="#common-questions" aria-hidden="true">#</a> Common Questions</h2><h3 id="can-i-use-it-in-multiplayer" tabindex="-1"><a class="header-anchor" href="#can-i-use-it-in-multiplayer" aria-hidden="true">#</a> Can I use it in multiplayer?</h3><p>Yes. The server and client must both install this mod. (This mod is not a plugin and cannot be used on Bukkit, Spigot or Paper.)</p><h3 id="sodium-compatibility" tabindex="-1"><a class="header-anchor" href="#sodium-compatibility" aria-hidden="true">#</a> Sodium Compatibility?</h3><p>In MC 1.19, the latest version of ImmPtl is roughly compatible with Sodium 0.4.2. (There is no guarantee that future versions of Sodium will be compatible.)</p><p>In MC 1.18.2, the latest version of ImmPtl is roughly compatible with Sodium 0.4.1.</p><p>In MC 1.17.1, the latest version of ImmPtl is roughly compatible with Sodium 0.3.4.</p><p>In 1.16.5 you can use <a href="https://github.com/qouteall/sodium-fabric/releases" target="_blank" rel="noopener noreferrer">this</a>.</p><h3 id="will-the-portal-impact-performance" tabindex="-1"><a class="header-anchor" href="#will-the-portal-impact-performance" aria-hidden="true">#</a> Will the portal impact performance?</h3><p>Yes. Portals will make the game load more chunks and render more things, it will definitely impact performance, especially with dimension stack, although ImmPtl already have some optimizations to mitigate the performance impact.</p><p>You can use Sodium (but not all Sodium versions are compatible with ImmPtl, see the above).</p><p>If it shows &quot;Memory not enough&quot; warning, you can <a href="https://filmora.wondershare.com/game-recording/how-to-allocate-more-ram-to-minecraft.html" target="_blank" rel="noopener noreferrer">allocate more RAM to Minecraft</a>.</p><h3 id="which-mods-are-incompatible-with-immptl" tabindex="-1"><a class="header-anchor" href="#which-mods-are-incompatible-with-immptl" aria-hidden="true">#</a> Which mods are incompatible with ImmPtl?</h3><p>This mod changes rendering, chunk loading and networking mechanics so it will be incompatible with some mods.</p><p><a href="https://github.com/qouteall/ImmersivePortalsMod/issues?q=is%3Aissue+is%3Aopen+label%3A%22Mod+Compatibility%22" target="_blank" rel="noopener noreferrer">Known compatibility issues</a></p><p>Immersive Portals may &quot;break&quot; some mod&#39;s functionality. <strong>This is not intentional</strong>. Because this mod allows loading multiple dimensions in client, another mod that assume the client has only one dimension will break.</p><h3 id="where-to-report-bugs-or-compatibility-issues" tabindex="-1"><a class="header-anchor" href="#where-to-report-bugs-or-compatibility-issues" aria-hidden="true">#</a> Where to report bugs or compatibility issues?</h3><p><a href="https://github.com/qouteall/ImmersivePortalsMod/issues" target="_blank" rel="noopener noreferrer">Report Issues</a></p><p>This mod is very complex and is only mainly developed by one person at spare time. Expect it to have some issues. But I will try to fix severe issues quickly. <a href="https://www.patreon.com/qouteall" target="_blank" rel="noopener noreferrer">Support qouteall on Patreon</a></p><h3 id="how-to-integrate-with-other-mod-s-portals" tabindex="-1"><a class="header-anchor" href="#how-to-integrate-with-other-mod-s-portals" aria-hidden="true">#</a> How to integrate with other mod&#39;s portals?</h3><p>You can use <a href="./Datapack-Based-Custom-Portal-Generation#convert_vanilla_nether_portaljson-convent-vanilla-nether-portals-into-see-through-portals-if-the-shapes-are-compatible">datapack</a> to make it convert other mod&#39;s portals into see-through portals.</p><h3 id="how-to-make-portal-helper-craft-able-in-survival" tabindex="-1"><a class="header-anchor" href="#how-to-make-portal-helper-craft-able-in-survival" aria-hidden="true">#</a> How to make portal helper craft-able in survival?</h3><p><a href="./Portal-Customization#how-to-use-similar-functionality-in-survival-mode">Check this</a></p><h3 id="the-nether-portal-is-not-see-through" tabindex="-1"><a class="header-anchor" href="#the-nether-portal-is-not-see-through" aria-hidden="true">#</a> The nether portal is not see-through.</h3><p>This mod does not change existing vanilla portals. You need to light new portals.</p><h3 id="the-nether-portal-does-not-link" tabindex="-1"><a class="header-anchor" href="#the-nether-portal-does-not-link" aria-hidden="true">#</a> The nether portal does not link.</h3><p>It can only link to an empty obsidian frame with the same shape and orientation (unless you change the nether portal mode to <code>adaptive</code>). It will not link to a vanilla nether portal.</p><h3 id="why-is-the-forge-version-not-being-supported" tabindex="-1"><a class="header-anchor" href="#why-is-the-forge-version-not-being-supported" aria-hidden="true">#</a> Why is the Forge version not being supported?</h3><p>This mod is just a hobby project. When people ask for the Forge version they actually ask it to be compatible with many Forge mods. However maintaining compatibility with some Fabric mods is already a huge work. Maintaining the Forge version turned out to be giving me bad experiences so I stopped maintaining the Forge version.</p><p>(There is a very small chance that I restart supporting the Forge version.)</p><p>This mod is in Apache 2.0 license and you are free to develop its Forge version. If you want to develop the Forge version, you can ask me for help.</p>',34),n=[r];function s(h,l){return t(),o("div",null,n)}var d=e(i,[["render",s],["__file","index.html.vue"]]);export{d as default};
